evaluators.evaluation_logic:
const checkpoints = [];

// Load data
let appts = [];
let slots = [];
let services = [];
let metadata = null;
try {
  appts = JSON.parse(localStorage.getItem('appointment_requests') || '[]') || [];
  slots = JSON.parse(localStorage.getItem('appointment_slots') || '[]') || [];
  services = JSON.parse(localStorage.getItem('services') || '[]') || [];
  metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');
} catch (e) {
  appts = [];
  slots = [];
  services = [];
  metadata = null;
}

// Determine baseline date and next calendar week's Monday–Friday range
let baselineDateStr = metadata && metadata.baselineDate ? metadata.baselineDate : '2026-03-03';
const baseline = new Date(baselineDateStr + 'T00:00:00');
const day = baseline.getDay(); // 0=Sun..6=Sat
let daysUntilNextMonday = (8 - day) % 7;
if (daysUntilNextMonday === 0) {
  daysUntilNextMonday = 7; // ensure "next" week, not current
}
const nextMonday = new Date(baseline);
nextMonday.setDate(baseline.getDate() + daysUntilNextMonday);
const nextFriday = new Date(nextMonday);
nextFriday.setDate(nextMonday.getDate() + 4);

// Find adult preventive cleaning services
const adultCleaningServiceIds = services
  .filter(function (s) {
    return s && s.is_active && s.category === 'preventive' && s.service_subtype === 'cleaning' && s.applies_to_adult;
  })
  .map(function (s) { return s.id; });

// Qualifying weekday evening slots at Downtown during next week
let qualifyingSlots = slots.filter(function (slot) {
  if (!slot || !slot.is_available) return false;
  if (slot.location_id !== 'downtown') return false;
  if (adultCleaningServiceIds.indexOf(slot.service_id) === -1) return false;
  if (slot.day_of_week === 'saturday' || slot.day_of_week === 'sunday') return false;
  if (slot.part_of_day !== 'evening') return false;
  const sd = new Date(slot.start_datetime);
  if (sd < nextMonday || sd > nextFriday) return false;
  return true;
});

// Find earliest qualifying slot
qualifyingSlots.sort(function (a, b) {
  return new Date(a.start_datetime) - new Date(b.start_datetime);
});
const earliestSlotId = qualifyingSlots.length ? qualifyingSlots[0].id : null;

let hasAnyQualifyingBooking = false;
let hasEarliestBooking = false;

appts.forEach(function (req) {
  if (!req) return;
  if (req.age_group !== 'adult') return;
  if (adultCleaningServiceIds.indexOf(req.service_id) === -1) return;
  if (req.location_id !== 'downtown') return;
  if (!req.appointment_slot_id) return;
  const slot = slots.find(function (s) { return s && s.id === req.appointment_slot_id; }) || null;
  if (!slot) return;

  const isQualSlot = qualifyingSlots.some(function (s) { return s.id === slot.id; });
  if (isQualSlot) {
    hasAnyQualifyingBooking = true;
    if (earliestSlotId && slot.id === earliestSlotId) {
      hasEarliestBooking = true;
    }
  }
});

// CP1: Booked any qualifying weekday evening adult cleaning next week at Downtown (0.5)
checkpoints.push({ passed: hasAnyQualifyingBooking, weight: 0.5 });
// CP2: Booked the earliest such qualifying slot (0.5)
checkpoints.push({ passed: hasEarliestBooking, weight: 0.5 });

return checkpoints.reduce(function (sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];

let submissions = [];
let services = [];
try {
  submissions = JSON.parse(localStorage.getItem('contact_submissions') || '[]') || [];
  services = JSON.parse(localStorage.getItem('services') || '[]') || [];
} catch (e) {
  submissions = [];
  services = [];
}

// Identify molar root canal service
const rootService = services.find(function (s) {
  return s && s.category === 'restorative' && s.service_subtype === 'root_canal' && s.tooth_type === 'molar';
}) || null;

// Identify qualifying molar crown options (<= $1,200)
const crownServices = services.filter(function (s) {
  return (
    s &&
    s.category === 'restorative' &&
    s.service_subtype === 'crown' &&
    s.tooth_type === 'molar' &&
    typeof s.uninsured_price === 'number' &&
    s.uninsured_price <= 1200
  );
});

let hasQualSubmission = false;
let hasCorrectTotal = false;

if (rootService && crownServices.length) {
  submissions.forEach(function (cs) {
    if (!cs) return;
    if (cs.submission_type !== 'cost_estimate') return;
    if (cs.is_uninsured !== true) return;
    if (typeof cs.total_estimated_cost !== 'number') return;
    if (!Array.isArray(cs.related_service_ids)) return;

    const hasRoot = cs.related_service_ids.indexOf(rootService.id) !== -1;
    if (!hasRoot) return;

    // Crown(s) in this submission that meet the price criterion
    const crownsInSubmission = crownServices.filter(function (c) {
      return cs.related_service_ids.indexOf(c.id) !== -1;
    });
    if (!crownsInSubmission.length) return;

    if (cs.total_estimated_cost <= 2500) {
      hasQualSubmission = true;
    }

    crownsInSubmission.forEach(function (crown) {
      const expectedTotal = rootService.uninsured_price + crown.uninsured_price;
      if (expectedTotal <= 2500 && cs.total_estimated_cost === expectedTotal) {
        hasCorrectTotal = true;
      }
    });
  });
}

// CP1: Submitted an uninsured cost estimate combining molar root canal + qualifying molar crown with total <= $2,500 (0.5)
checkpoints.push({ passed: hasQualSubmission, weight: 0.5 });
// CP2: The submitted total exactly matches root canal price + a qualifying crown price (0.5)
checkpoints.push({ passed: hasCorrectTotal, weight: 0.5 });

return checkpoints.reduce(function (sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];

let appts = [];
let slots = [];
let dentists = [];
let metadata = null;
try {
  appts = JSON.parse(localStorage.getItem('appointment_requests') || '[]') || [];
  slots = JSON.parse(localStorage.getItem('appointment_slots') || '[]') || [];
  dentists = JSON.parse(localStorage.getItem('dentists') || '[]') || [];
  metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');
} catch (e) {
  appts = [];
  slots = [];
  dentists = [];
  metadata = null;
}

// Determine upcoming Saturday relative to baseline
let baselineDateStr = metadata && metadata.baselineDate ? metadata.baselineDate : '2026-03-03';
const baseline = new Date(baselineDateStr + 'T00:00:00');
const day = baseline.getDay(); // 0=Sun..6=Sat
let daysUntilSaturday = (6 - day + 7) % 7;
if (daysUntilSaturday === 0) {
  daysUntilSaturday = 7; // ensure "upcoming" Saturday, not same day
}
const upcomingSaturday = new Date(baseline);
upcomingSaturday.setDate(baseline.getDate() + daysUntilSaturday);
const upcomingSatYMD = upcomingSaturday.toISOString().slice(0, 10);

// Qualifying pediatric dentists
const qualifyingDentistIds = dentists
  .filter(function (d) {
    return (
      d &&
      d.active &&
      Array.isArray(d.specialties) && d.specialties.indexOf('pediatric_dentistry') !== -1 &&
      d.accepts_children_under_12 === true &&
      d.is_pediatric_specialist === true &&
      d.offers_saturday_hours === true &&
      typeof d.rating === 'number' && d.rating >= 4.0
    );
  })
  .map(function (d) { return d.id; });

let hasAnySaturdayMatch = false;
let hasUpcomingSaturdayMatch = false;

appts.forEach(function (req) {
  if (!req) return;
  if (req.age_group !== 'child') return;
  if (req.patient_age !== 7) return;
  if (!req.appointment_slot_id) return;

  const slot = slots.find(function (s) { return s && s.id === req.appointment_slot_id; }) || null;
  if (!slot) return;

  const startTimePart = (slot.start_datetime && slot.start_datetime.split('T')[1]) ? slot.start_datetime.split('T')[1].slice(0, 5) : '';
  const isQualDentist = qualifyingDentistIds.indexOf(slot.dentist_id) !== -1;

  if (slot.day_of_week === 'saturday' && startTimePart >= '11:00' && isQualDentist) {
    hasAnySaturdayMatch = true;
    if (slot.start_datetime.slice(0, 10) === upcomingSatYMD) {
      hasUpcomingSaturdayMatch = true;
    }
  }
});

// CP1: Booked a Saturday >=11:00 AM appointment for a 7-year-old with a qualifying pediatric dentist (any Saturday) (0.6)
checkpoints.push({ passed: hasAnySaturdayMatch, weight: 0.6 });
// CP2: That booking is specifically for the upcoming Saturday (0.4)
checkpoints.push({ passed: hasUpcomingSaturdayMatch, weight: 0.4 });

return checkpoints.reduce(function (sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];

let appts = [];
let orthoOptions = [];
try {
  appts = JSON.parse(localStorage.getItem('appointment_requests') || '[]') || [];
  orthoOptions = JSON.parse(localStorage.getItem('orthodontic_treatment_options') || '[]') || [];
} catch (e) {
  appts = [];
  orthoOptions = [];
}

// Qualifying adult clear aligner options: nearly invisible, currently offered, average duration <= 24 months
const qualifyingOptions = orthoOptions.filter(function (o) {
  return (
    o &&
    o.is_currently_offered === true &&
    o.is_nearly_invisible === true &&
    o.is_for_adults === true &&
    typeof o.average_duration_months === 'number' && o.average_duration_months <= 24
  );
});

const relatedServiceIds = [];
qualifyingOptions.forEach(function (o) {
  if (o.related_service_id && relatedServiceIds.indexOf(o.related_service_id) === -1) {
    relatedServiceIds.push(o.related_service_id);
  }
});

let hasConsultWithPrefs = false;
let hasInvisalignMention = false;

appts.forEach(function (req) {
  if (!req) return;
  if (req.age_group !== 'adult') return;
  if (relatedServiceIds.indexOf(req.service_id) === -1) return;

  const notes = (req.notes || '').toLowerCase();
  const mentionsClearAligner = notes.indexOf('clear aligner') !== -1 || notes.indexOf('clear aligners') !== -1;
  const mentionsInvisible = notes.indexOf('nearly invisible') !== -1 || notes.indexOf('invisible') !== -1;
  const mentionsShortDuration = notes.indexOf('months') !== -1 || notes.indexOf('< 24') !== -1 || notes.indexOf('under 24') !== -1;
  const mentionsInvisalign = notes.indexOf('invisalign') !== -1;

  const expressesPrefs = mentionsClearAligner || (mentionsInvisible && mentionsShortDuration) || mentionsInvisalign;

  if (expressesPrefs) {
    hasConsultWithPrefs = true;
  }
  if (mentionsInvisalign) {
    hasInvisalignMention = true;
  }
});

// CP1: Adult consult for a qualifying clear aligner option with notes expressing preference for nearly invisible/clear aligners and shorter treatment (0.6)
checkpoints.push({ passed: hasConsultWithPrefs, weight: 0.6 });
// CP2: Notes explicitly mention "Invisalign", indicating selection of the Invisalign adult option (0.4)
checkpoints.push({ passed: hasInvisalignMention, weight: 0.4 });

return checkpoints.reduce(function (sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];

let appts = [];
let plans = [];
let services = [];
try {
  appts = JSON.parse(localStorage.getItem('appointment_requests') || '[]') || [];
  plans = JSON.parse(localStorage.getItem('insurance_plans') || '[]') || [];
  services = JSON.parse(localStorage.getItem('services') || '[]') || [];
} catch (e) {
  appts = [];
  plans = [];
  services = [];
}

// Determine the two primary plans (by display_order) and which has higher preventive coverage
const sortedPlans = plans.slice().sort(function (a, b) {
  return (a && a.display_order || 0) - (b && b.display_order || 0);
});
const planA = sortedPlans[0] || null;
const planB = sortedPlans[1] || null;
let betterPlan = null;
if (planA && planB && typeof planA.preventive_coverage_percent === 'number' && typeof planB.preventive_coverage_percent === 'number') {
  betterPlan = planA.preventive_coverage_percent >= planB.preventive_coverage_percent ? planA : planB;
}

// Identify adult routine cleaning service
const adultCleaningServices = services.filter(function (s) {
  return s && s.is_active && s.category === 'preventive' && s.service_subtype === 'cleaning' && s.applies_to_adult;
});
let routineCleaning = null;
adultCleaningServices.forEach(function (s) {
  if (routineCleaning) return;
  const name = (s.name || '').toLowerCase();
  const slug = (s.slug || '').toLowerCase();
  if (name.indexOf('routine') !== -1 || slug.indexOf('preventive-cleaning') !== -1) {
    routineCleaning = s;
  }
});
if (!routineCleaning && adultCleaningServices.length) {
  routineCleaning = adultCleaningServices[0];
}

let hasCorrectPlan = false;
let hasCorrectPlanFromInsurancePage = false;

if (betterPlan && routineCleaning) {
  appts.forEach(function (req) {
    if (!req) return;
    if (req.service_id !== routineCleaning.id) return;
    if (req.age_group !== 'adult') return;
    if (req.insurance_plan_id !== betterPlan.id) return;

    hasCorrectPlan = true;
    if (req.source_page === 'insurance_page') {
      hasCorrectPlanFromInsurancePage = true;
    }
  });
}

// CP1: Booked an adult routine cleaning using the plan with higher preventive coverage of the two key plans (0.6)
checkpoints.push({ passed: hasCorrectPlan, weight: 0.6 });
// CP2: That booking was initiated from the insurance page (0.4)
checkpoints.push({ passed: hasCorrectPlanFromInsurancePage, weight: 0.4 });

return checkpoints.reduce(function (sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);

const checklists = [];

let messages = [];
let instructions = [];
try {
  messages = JSON.parse(localStorage.getItem('emergency_messages') || '[]') || [];
  instructions = JSON.parse(localStorage.getItem('emergency_instructions') || '[]') || [];
} catch (e) {
  messages = [];
  instructions = [];
}

const severeInstr = instructions.find(function (i) {
  return i && i.condition_type === 'severe_toothache';
}) || null;
const afterHoursNumber = severeInstr ? severeInstr.after_hours_phone_number : null;

let hasCoreMatch = false;
let hasDetailedMatch = false;

messages.forEach(function (msg) {
  if (!msg) return;
  if (msg.condition_type !== 'severe_toothache') return;
  if (!afterHoursNumber || msg.emergency_phone_number_displayed !== afterHoursNumber) return;
  if (msg.callback_requested !== true) return;
  if (msg.callback_time_preference !== 'tonight') return;

  const timeText = (msg.event_time_text || '').toLowerCase();
  if (timeText.indexOf('9') === -1 || timeText.indexOf('pm') === -1) return;

  hasCoreMatch = true;

  const descRaw = msg.description || '';
  const desc = descRaw.toLowerCase();
  const mentionsTime = (desc.indexOf('9') !== -1 && desc.indexOf('pm') !== -1) || desc.indexOf('9:00') !== -1;
  const mentionsNumber = descRaw.indexOf(afterHoursNumber) !== -1;

  if (mentionsTime && mentionsNumber) {
    hasDetailedMatch = true;
  }
});

// CP1: Emergency message for severe toothache after hours with 9 PM time, correct after-hours number, and same-night callback requested (0.7)
checklists.push({ passed: hasCoreMatch, weight: 0.7 });
// CP2: The message description itself mentions the ~9 PM time and includes the after-hours phone number (0.3)
checklists.push({ passed: hasDetailedMatch, weight: 0.3 });

return checklists.reduce(function (sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];

let appts = [];
let slots = [];
let guides = [];
try {
  appts = JSON.parse(localStorage.getItem('appointment_requests') || '[]') || [];
  slots = JSON.parse(localStorage.getItem('appointment_slots') || '[]') || [];
  guides = JSON.parse(localStorage.getItem('new_patient_guides') || '[]') || [];
} catch (e) {
  appts = [];
  slots = [];
  guides = [];
}

const childGuide = guides.find(function (g) {
  return g && g.patient_group === 'child_under_13';
}) || null;
const recommendedServiceId = childGuide ? childGuide.recommended_service_id : null;

let requestsServiceAndAge = [];
let fullyQualifyingRequests = [];

if (recommendedServiceId) {
  appts.forEach(function (req) {
    if (!req) return;
    if (req.age_group !== 'child') return;
    if (req.patient_age !== 10) return;
    if (req.service_id !== recommendedServiceId) return;

    requestsServiceAndAge.push(req);

    if (!req.appointment_slot_id) return;
    const slot = slots.find(function (s) { return s && s.id === req.appointment_slot_id; }) || null;
    if (!slot) return;

    const timePart = (slot.start_datetime && slot.start_datetime.split('T')[1]) ? slot.start_datetime.split('T')[1].slice(0, 5) : '';
    const isWeekday = slot.day_of_week !== 'saturday' && slot.day_of_week !== 'sunday';
    const inAfternoonWindow = slot.part_of_day === 'afternoon' && timePart >= '13:00' && timePart <= '16:00';

    if (isWeekday && inAfternoonWindow) {
      fullyQualifyingRequests.push(req);
    }
  });
}

// CP1: Booked the recommended child new patient exam for a 10-year-old (service + age) (0.4)
checkpoints.push({ passed: requestsServiceAndAge.length > 0, weight: 0.4 });
// CP2: That booking is on a weekday afternoon between 1:00 PM and 4:00 PM via a qualifying slot (0.6)
checkpoints.push({ passed: fullyQualifyingRequests.length > 0, weight: 0.6 });

return checkpoints.reduce(function (sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];

let appts = [];
let slots = [];
let promotions = [];
let services = [];
let metadata = null;
try {
  appts = JSON.parse(localStorage.getItem('appointment_requests') || '[]') || [];
  slots = JSON.parse(localStorage.getItem('appointment_slots') || '[]') || [];
  promotions = JSON.parse(localStorage.getItem('promotions') || '[]') || [];
  services = JSON.parse(localStorage.getItem('services') || '[]') || [];
  metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');
} catch (e) {
  appts = [];
  slots = [];
  promotions = [];
  services = [];
  metadata = null;
}

// Current month based on baseline date
let baselineDateStr = metadata && metadata.baselineDate ? metadata.baselineDate : '2026-03-03';
const currentMonthStr = baselineDateStr.slice(0, 7); // 'YYYY-MM'

// Qualifying whitening promotions: cosmetic whitening, active, new-patient only, price <= 200
const qualifyingPromos = promotions.filter(function (p) {
  return (
    p &&
    p.status === 'active' &&
    p.promotion_type === 'whitening' &&
    p.is_new_patient_only === true &&
    typeof p.price === 'number' && p.price <= 200
  );
});
const qualifyingPromoIds = qualifyingPromos.map(function (p) { return p.id; });

// Identify whitening consultation service
let whiteningConsult = null;
services.forEach(function (s) {
  if (!s || whiteningConsult) return;
  const name = (s.name || '').toLowerCase();
  const slug = (s.slug || '').toLowerCase();
  if (s.service_subtype === 'consultation' && (name.indexOf('whitening') !== -1 || slug.indexOf('whitening') !== -1)) {
    whiteningConsult = s;
  }
});

let hasConsultThisMonthMorning = false;
let hasConsultWithPromo = false;

if (whiteningConsult) {
  appts.forEach(function (req) {
    if (!req) return;
    if (req.service_id !== whiteningConsult.id) return;
    if (req.patient_type !== 'new_patient') return;
    if (!req.appointment_slot_id) return;

    const slot = slots.find(function (s) { return s && s.id === req.appointment_slot_id; }) || null;
    if (!slot) return;

    const datePart = slot.start_datetime ? slot.start_datetime.slice(0, 10) : '';
    const monthPart = datePart.slice(0, 7);
    const timePart = (slot.start_datetime && slot.start_datetime.split('T')[1]) ? slot.start_datetime.split('T')[1].slice(0, 5) : '';

    const isThisMonthMorning = monthPart === currentMonthStr && slot.part_of_day === 'morning' && timePart < '11:00';

    if (isThisMonthMorning) {
      hasConsultThisMonthMorning = true;
      if (qualifyingPromoIds.indexOf(req.promotion_id) !== -1 && req.is_new_patient_promotion === true) {
        hasConsultWithPromo = true;
      }
    }
  });
}

// CP1: New-patient whitening consultation this month in a morning slot before 11:00 AM (0.6)
checkpoints.push({ passed: hasConsultThisMonthMorning, weight: 0.6 });
// CP2: That consultation is linked to a qualifying whitening promotion under $200 marked as a new-patient promotion (0.4)
checkpoints.push({ passed: hasConsultWithPromo, weight: 0.4 });

return checkpoints.reduce(function (sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);
